const body = ($json && $json.body) || {};
const taskId = typeof body.task_id === 'string' ? body.task_id.trim() : '';

if (!taskId || !/^TASK-[A-Za-z0-9]+$/.test(taskId)) {
  return {
    json: {
      valid: false,
      reply_text: '未能识别任务编号，请使用「查询 TASK-XXXXXXXXXXXX」格式。',
    },
  };
}

return {
  json: {
    valid: true,
    task_id: taskId,
  },
};

const STATUS_TEXT = { pending: '等待执行', running: '执行中', completed: '已完成', failed: '失败' };

function extractStatusCode(errorLike) {
  const error = (errorLike && errorLike.error) || {};
  const candidates = [
    error.httpCode,
    error.statusCode,
    error.status,
    error.cause && error.cause.response && error.cause.response.status,
  ];
  for (const candidate of candidates) {
    if (candidate === undefined || candidate === null) continue;
    const parsed = parseInt(candidate, 10);
    if (!Number.isNaN(parsed)) return parsed;
  }
  return null;
}

const validateItem = $('Code｜校验 task_id').item.json;

if (validateItem.valid === false) {
  return {
    json: {
      ok: true,
      task_id: null,
      status: null,
      status_text: null,
      reply_text: validateItem.reply_text,
    },
  };
}

const item = $input.first().json;

if (item && typeof item === 'object' && item.id && item.status) {
  const statusText = STATUS_TEXT[item.status] || item.status;
  let reply = `任务编号：${item.id}\n当前状态：${statusText}\nAI 员工：${item.assigned_agent || '（未指定）'}\n优先级：${item.priority}\n创建时间：${item.created_at}`;
  if (item.completed_at) {
    reply += `\n完成时间：${item.completed_at}`;
  }
  if (item.status === 'completed') {
    reply += `\n\n执行结果：\n${item.safe_result}`;
  } else if (item.status === 'failed') {
    reply += `\n\n错误信息：\n${item.safe_error}`;
  }
  return {
    json: {
      ok: true,
      task_id: item.id,
      status: item.status,
      status_text: statusText,
      reply_text: reply,
    },
  };
}

const statusCode = extractStatusCode(item);

if (statusCode === 404) {
  return {
    json: {
      ok: true,
      task_id: validateItem.task_id,
      status: null,
      status_text: null,
      reply_text: `未找到任务：${validateItem.task_id}，请检查任务编号是否正确。`,
    },
  };
}

if (statusCode === 401) {
  return {
    json: {
      ok: false,
      task_id: validateItem.task_id,
      status: null,
      status_text: null,
      reply_text: '系统鉴权异常，请联系管理员。',
    },
  };
}

return {
  json: {
    ok: false,
    task_id: validateItem.task_id,
    status: null,
    status_text: null,
    reply_text: '查询暂时失败，请稍后重试。',
  },
};
